INSERT INTO rules (id, name, description, severity, action, category_id, rule_type, applicable_stages, detection_config, enabled, source, bundle_series, sdk_version)
SELECT 'SEC-01', 'Hardcoded Cloud Credentials', 'Detect hardcoded cloud platform credentials, API keys, tokens, and private keys in source code.', 'P0', 'warn', 3, 'code_review', '["batch"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "AKIA[0-9A-Z]{16}\\b", "confidence": 0.95}, {"type": "regex", "value": "ghp_[0-9A-Za-z]{36,40}\\b", "confidence": 0.95}, {"type": "regex", "value": "gh[oausr]_[0-9A-Za-z]{36}\\b", "confidence": 0.9}, {"type": "regex", "value": "glpat-[0-9A-Za-z\\-_]{20,40}\\b", "confidence": 0.9}, {"type": "regex", "value": "sk-[a-zA-Z0-9]{20,50}\\b", "confidence": 0.9}, {"type": "regex", "value": "sk-ant-[a-zA-Z0-9]{40,60}\\b", "confidence": 0.9}, {"type": "regex", "value": "(?i)-----BEGIN\\s+(?:RSA\\s+)?PRIVATE\\s+KEY-----", "confidence": 0.95}, {"type": "regex", "value": "(?i)-----BEGIN\\s+(?:OPEN)?SSH\\s+PRIVATE\\s+KEY-----", "confidence": 0.95}, {"type": "regex", "value": "(?i)-----BEGIN\\s+PGP\\s+(?:PRIVATE\\s+)?KEY\\s+BLOCK-----", "confidence": 0.9}, {"type": "regex", "value": "\\beyJ[A-Za-z0-9\\-_]+\\.[A-Za-z0-9\\-_]+\\.[A-Za-z0-9\\-_]+\\b", "confidence": 0.7}, {"type": "regex", "value": "sk_live_[a-zA-Z0-9]{24,}\\b", "confidence": 0.95}, {"type": "regex", "value": "pk_live_[a-zA-Z0-9]{24,}\\b", "confidence": 0.9}, {"type": "regex", "value": "\\bAIza[0-9A-Za-z\\-_]{35}\\b", "confidence": 0.9}]}', TRUE, 'sdk', 'SEC', 1
WHERE NOT EXISTS (SELECT 1 FROM rules WHERE id = 'SEC-01');
