SELECT 'SEC-02', 'Hardcoded Passwords / Connection Strings', 'Detect hardcoded database connection strings, message queue URLs, and SSH URIs containing passwords.', 'P0', 'warn', 3, 'code_review', '["batch"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "[a-zA-Z]+://[^:]+:[^@]+@[^/\\s]+", "confidence": 0.85}, {"type": "regex", "value": "(?i)(?:jdbc|mysql|postgres|mongodb|redis|rediss|rabbitmq|amqp|kafka|sqs|memcache|hbase|cassandra)://[^\\s''\"]+", "confidence": 0.8}, {"type": "regex", "value": "(?i)DefaultEndpointsProtocol=https;AccountName=[^;]+;AccountKey=[^;]+", "confidence": 0.9}, {"type": "regex", "value": "ssh://[^:]+:[^@]+@", "confidence": 0.85}, {"type": "regex", "value": "(?i)(?:password|passwd|pwd)\\s*[:=]\\s*[''\"][^''\"]{3,}[''\"]", "confidence": 0.6}]}', TRUE, 'sdk', 'SEC', 1
WHERE NOT EXISTS (SELECT 1 FROM rules WHERE id = 'SEC-02');
