SELECT 'I-25', 'NoSQL Injection', 'Detect NoSQL injection features: MongoDB $where/$ne/$gt/$regex operator injection, JSON injection, REST API parameter injection, Couchbase N1QL injection, Firebase bypass', 'P2', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "\\$ne\\s*[:=]\\s*(?:null|\\\"|\\''|\\d|true|false)", "confidence": 0.6}, {"type": "regex", "value": "\\$gt\\s*[:=]\\s*(?:\\\"|\\''|\\d)", "confidence": 0.6}, {"type": "regex", "value": "\\$regex\\s*[:=]\\s*[''\"]\\.*[''\"]", "confidence": 0.6}, {"type": "keyword", "value": "$where", "confidence": 0.5}, {"type": "keyword", "value": "$nin", "confidence": 0.4}, {"type": "regex", "value": "\\$ne\\s*:", "confidence": 0.6}, {"type": "regex", "value": "\\$ne\\s*:", "confidence": 0.6}, {"type": "regex", "value": "\\$ne[\"\\'']?\\s*:", "confidence": 0.6}]}', TRUE, 'sdk', 'I', 1
WHERE NOT EXISTS (SELECT 1 FROM rules WHERE id = 'I-25');
INSERT INTO rules (id, name, description, severity, action, category_id, rule_type, applicable_stages, detection_config, enabled, source, bundle_series, sdk_version)
SELECT 'I-26', 'SSTI (Server-Side Template Injection)', 'Detect template injection payloads: Jinja2, Handlebars/Mustache, Mako, Freemarker, Velocity, Thymeleaf, Twig, Smarty, Pug, Nunjucks, Jade', 'P2', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "\\{\\{\\s*(?:config|self|class|__class__|__subclasses__|__builtins__|__globals__|__mro__|__init__|__import__)", "confidence": 0.75}, {"type": "regex", "value": "\\$\\{[A-Za-z_][A-Za-z0-9_.()]*\\}", "confidence": 0.5}, {"type": "regex", "value": "\\{\\{\\s*[A-Za-z_][A-Za-z0-9_.()]*\\s*\\|\\s*(?:attr|join|map|select|reject|first|last|random|length|string)", "confidence": 0.7}, {"type": "regex", "value": "\\$\\{self\\.module\\.cache\\}", "confidence": 0.8}, {"type": "regex", "value": "<#assign\\s+[A-Za-z_][A-Za-z0-9_]*\\s*=", "confidence": 0.5}, {"type": "regex", "value": "#set\\s*\\(\\s*\\$[A-Za-z_]", "confidence": 0.5}, {"type": "regex", "value": "\\{\\{\\s*[A-Za-z_][A-Za-z0-9_.]*\\s*\\(\\s*\\)", "confidence": 0.5}]}', TRUE, 'sdk', 'I', 1
WHERE NOT EXISTS (SELECT 1 FROM rules WHERE id = 'I-26');
