SELECT 'I-27', 'XXE / XML Injection', 'Detect XML External Entity injection: DOCTYPE, ENTITY, SYSTEM file://, DTD external reference, XInclude, SOAP XML injection, SVG XXE', 'P2', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "<!DOCTYPE\\s+[A-Za-z_][A-Za-z0-9_.]*\\s+\\[\\s*<!ENTITY\\s+", "confidence": 0.85}, {"type": "regex", "value": "<!ENTITY\\s+[A-Za-z_][A-Za-z0-9_.]*\\s+SYSTEM\\s+[''\"]", "confidence": 0.85}, {"type": "regex", "value": "<!ENTITY\\s+[A-Za-z_][A-Za-z0-9_.]*\\s+PUBLIC\\s+[''\"]", "confidence": 0.8}, {"type": "regex", "value": "\\bxi:include\\s+(?:href|parse|xpointer)", "confidence": 0.7}, {"type": "regex", "value": "\\bxmlns:xi\\s*=\\s*[''\"]http://www\\.w3\\.org/2001/XInclude[''\"]", "confidence": 0.5}]}', TRUE, 'sdk', 'I', 1
