WHERE NOT EXISTS (SELECT 1 FROM rules WHERE id = 'I-36');
INSERT INTO rules (id, name, description, severity, action, category_id, rule_type, applicable_stages, detection_config, enabled, source, bundle_series, sdk_version)
SELECT 'I-37', 'Large Binary File', 'Detect user referencing large/binary files: .db/.sqlite, .exe/.dll/.so, .zip/.tar.gz/.7z/.rar, .iso/.dmg, .bin/.dat, .pcap, .min.js, .pyc/.class, .dmp, .vmdk/.qcow2', 'P1', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "(?:\\.db|\\.sqlite|\\.sqlite3|\\.exe|\\.dll|\\.so|\\.dylib|\\.zip|\\.tar(?:\\.gz|\\.bz2|\\.xz)?|\\.7z|\\.rar|\\.iso|\\.dmg|\\.bin|\\.dat|\\.pcap|\\.pcapng|\\.min\\.js|\\.pyc|\\.class|\\.dmp|\\.dump|\\.vmdk|\\.qcow2|\\.ova|\\.vdi)", "confidence": 0.4}, {"type": "regex", "value": "(?:read|open|view|analyze|examine|process|load|upload|import|extract|unzip|解压|读取|分析|打开|加载|上传|导入|处理)\\s*.*(?:binary|executable|large|big|huge|large\\s+file|二进制|可执行|大文件)", "confidence": 0.3}]}', TRUE, 'sdk', 'I', 1
WHERE NOT EXISTS (SELECT 1 FROM rules WHERE id = 'I-37');
INSERT INTO rules (id, name, description, severity, action, category_id, rule_type, applicable_stages, detection_config, enabled, source, bundle_series, sdk_version)
SELECT 'I-38', 'Zip Slip / Archive Extraction Risk', 'Detect path traversal risk in archive extraction: Zip Slip (../ in entry names), tar symlink escape, RAR absolute path attack', 'P2', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "keyword", "value": "../", "confidence": 0.3}, {"type": "keyword", "value": "zip slip", "confidence": 0.7}, {"type": "keyword", "value": "path traversal", "confidence": 0.5}, {"type": "regex", "value": "(?:extract|unzip|untar|decompress|解压|提取|展开).*(?:..\\/|%2e%2e%2f|..%2f)", "confidence": 0.6}]}', TRUE, 'sdk', 'I', 1
