SELECT 'I-39', 'Multi-modal / File-based Hidden Payload', 'Detect hidden attack instructions in non-plaintext files: image metadata steganography, PDF metadata, SVG malicious scripts, Office document macros, archive path traversal, Markdown/HTML hidden content', 'P1', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "regex", "value": "<script\\s+[^>]*>(?:<\\!\\[CDATA\\[)?\\s*(?:alert|eval|fetch|XMLHttpRequest|ActiveXObject)", "confidence": 0.7}, {"type": "regex", "value": "on(?:load|click|mouseover|focus|submit|error|unload|resize)\\s*=\\s*[''\"]", "confidence": 0.5}, {"type": "regex", "value": "<\\?xml[^>]*?>.*?<!DOCTYPE\\s+[^>]*?\\[.*?<!ENTITY", "confidence": 0.7}, {"type": "keyword", "value": "Sub AutoOpen()", "confidence": 0.7}, {"type": "keyword", "value": "Workbook_Open", "confidence": 0.6}, {"type": "keyword", "value": "Auto_Open", "confidence": 0.6}, {"type": "keyword", "value": "Document_Open", "confidence": 0.6}, {"type": "regex", "value": "<script[^>]*>.*?</script>", "confidence": 0.6}]}', TRUE, 'sdk', 'I', 1
