SELECT 'I-40', 'Proprietary Code / Copyright Ingestion', 'Detect user input that may infringe intellectual property: analyzing third-party closed-source code, reverse engineering binaries, deobfuscating copyrighted software, explaining NDA-protected code, reproducing competitor core logic', 'P2', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "keyword", "value": "reverse engineer", "confidence": 0.5}, {"type": "keyword", "value": "decompile", "confidence": 0.6}, {"type": "keyword", "value": "deobfuscate", "confidence": 0.6}, {"type": "keyword", "value": "proprietary", "confidence": 0.4}, {"type": "keyword", "value": "copyright", "confidence": 0.3}, {"type": "keyword", "value": "closed-source", "confidence": 0.5}, {"type": "regex", "value": "(?:analyze|analyse|explain|understand|examine|reverse)\\s+(?:this\\s+)?(?:binary|executable|compiled|obfuscated|minified|closed[-\\s]source|proprietary)", "confidence": 0.6}, {"type": "keyword", "value": "disassemble", "confidence": 0.6}, {"type": "keyword", "value": "反编译", "confidence": 0.6}, {"type": "keyword", "value": "逆向", "confidence": 0.5}, {"type": "keyword", "value": "NDA", "confidence": 0.3}]}', TRUE, 'sdk', 'I', 1
