SELECT 'I-41', 'Resource Exhaustion / Compression Bomb', 'Detect user inducing AI to consume excessive compute resources: zip bomb extraction, recursive expansion, giant output generation, self-referencing recursion, catastrophic backtracking', 'P1', 'warn', 1, 'io', '["input"]', '{"mode": "any", "patterns": [{"type": "keyword", "value": "zip bomb", "confidence": 0.8}, {"type": "keyword", "value": "42.zip", "confidence": 0.7}, {"type": "keyword", "value": "recursive", "confidence": 0.3}, {"type": "regex", "value": "(?:expand|extract|decompress|unzip|repeat|loop)\\s+(?:this|that|it|the\\s+file|the\\s+archive)\\s+(?:\\d{3,}|thousand|million|billion|10{2,})\\s*(?:times|iterations|rounds)", "confidence": 0.6}, {"type": "regex", "value": "(?:generate|create|produce|write|output|print|make)\\s+(?:an?\\s+)?(?:extremely|very|ultra|super|massively|enormously|incredibly)\\s+(?:large|long|big|huge|giant|massive|enormous)", "confidence": 0.4}]}', TRUE, 'sdk', 'I', 1
